+  helpTitle?: string;
+  helpLines?: string[];
+  envPrompt: string;
+  keepPrompt: string;
+  inputPrompt: string;
+  allowEnv?: (params: { cfg: OpenClawConfig; accountId: string }) => boolean;
+  inspect: (params: {
+    cfg: OpenClawConfig;
+    accountId: string;
+  }) => ChannelSetupWizardCredentialState;
+};
+
+export type ChannelSetupWizardAllowFromEntry = {
+  input: string;
+  resolved: boolean;
+  id: string | null;
+};
+
+export type ChannelSetupWizardAllowFrom = {
+  helpTitle?: string;
+  helpLines?: string[];
+  message: string;
+  placeholder?: string;
