+          cfg: next,
+          accountId,
+          allowFrom: unique,
+        });
+      }
+
+      return { cfg: next, accountId };
+    },
+    dmPolicy: wizard.dmPolicy,
+    disable: wizard.disable,
+    onAccountRecorded: wizard.onAccountRecorded,
+  };
+}

